import React, { createContext, useState, useContext, useEffect, useMemo } from 'react';
import { ThemeProvider as MuiThemeProvider, createTheme, responsiveFontSizes } from '@mui/material/styles';
import { CssBaseline } from '@mui/material';

// Типы темы
type ThemeMode = 'light' | 'dark';

// Контекст
interface ThemeContextType {
  mode: ThemeMode;
  toggleTheme: () => void;
  setMode: (mode: ThemeMode) => void;
}

// Создаем контекст
const ThemeContext = createContext<ThemeContextType>({
  mode: 'light',
  toggleTheme: () => {},
  setMode: () => {},
});

// Хук для использования контекста темы
export const useThemeContext = () => useContext(ThemeContext);

// Свойства провайдера темы
interface ThemeProviderProps {
  children: React.ReactNode;
}

// Провайдер темы
export const ThemeProvider: React.FC<ThemeProviderProps> = ({ children }) => {
  // Проверяем сохраненную тему или системные настройки
  const prefersDarkMode = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  const savedMode = localStorage.getItem('themeMode') as ThemeMode | null;
  
  // Устанавливаем начальное значение
  const [mode, setMode] = useState<ThemeMode>(savedMode || (prefersDarkMode ? 'dark' : 'light'));
  
  // Переключатель темы
  const toggleTheme = () => {
    setMode((prevMode) => (prevMode === 'light' ? 'dark' : 'light'));
  };
  
  // Устанавливаем конкретный режим
  const handleSetMode = (newMode: ThemeMode) => {
    setMode(newMode);
  };
  
  // Сохраняем выбранную тему
  useEffect(() => {
    localStorage.setItem('themeMode', mode);
  }, [mode]);
  
  // Создаем тему на основе выбранного режима
  const theme = useMemo(() => {
    let baseTheme = createTheme({
      palette: {
        mode,
        primary: {
          main: '#2196F3', // голубой
          light: '#64B5F6',
          dark: '#1976D2',
          contrastText: '#fff',
        },
        secondary: {
          main: '#FF4081', // розовый
          light: '#FF80AB',
          dark: '#F50057',
          contrastText: '#fff',
        },
        background: {
          default: mode === 'light' ? '#f5f7fa' : '#121212',
          paper: mode === 'light' ? '#ffffff' : '#1e1e1e',
        },
      },
      typography: {
        fontFamily: '"Roboto", "Arial", sans-serif',
        h1: {
          fontWeight: 700,
          fontSize: '2.5rem',
        },
        h2: {
          fontWeight: 700,
          fontSize: '2rem',
        },
        h3: {
          fontWeight: 600,
          fontSize: '1.75rem',
        },
        h4: {
          fontWeight: 600,
          fontSize: '1.5rem',
        },
        h5: {
          fontWeight: 600,
          fontSize: '1.25rem',
        },
        h6: {
          fontWeight: 600,
          fontSize: '1rem',
        },
        button: {
          textTransform: 'none',
          fontWeight: 600,
        },
      },
      shape: {
        borderRadius: 8,
      },
      components: {
        MuiButton: {
          styleOverrides: {
            root: {
              boxShadow: 'none',
              textTransform: 'none',
              borderRadius: 12,
              padding: '8px 16px',
              transition: 'all 0.3s ease',
              '&:hover': {
                boxShadow: mode === 'light' 
                  ? '0px 4px 8px rgba(0, 0, 0, 0.1)' 
                  : '0px 4px 8px rgba(255, 255, 255, 0.1)',
              },
            },
            containedPrimary: {
              background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
            },
          },
        },
        MuiCard: {
          styleOverrides: {
            root: {
              borderRadius: 16,
              boxShadow: mode === 'light' 
                ? '0px 4px 20px rgba(0, 0, 0, 0.08)' 
                : '0px 4px 20px rgba(0, 0, 0, 0.3)',
            },
          },
        },
        MuiAppBar: {
          styleOverrides: {
            root: {
              boxShadow: mode === 'light' 
                ? '0px 2px 10px rgba(0, 0, 0, 0.08)' 
                : '0px 2px 10px rgba(0, 0, 0, 0.3)',
            },
          },
        },
        MuiTextField: {
          styleOverrides: {
            root: {
              '& .MuiOutlinedInput-root': {
                borderRadius: 12,
              },
            },
          },
        },
        MuiPaper: {
          styleOverrides: {
            root: {
              backgroundImage: 'none',
            },
          },
        },
      },
    });
    
    // Делаем шрифты адаптивными
    return responsiveFontSizes(baseTheme);
  }, [mode]);
  
  const contextValue = {
    mode,
    toggleTheme,
    setMode: handleSetMode,
  };
  
  return (
    <ThemeContext.Provider value={contextValue}>
      <MuiThemeProvider theme={theme}>
        <CssBaseline />
        {children}
      </MuiThemeProvider>
    </ThemeContext.Provider>
  );
};

export default ThemeProvider;
